	static List<CapturedRegressionSnapshot> captureCurrentRegressionSnapshots(Path dataDir, Path outputDir)
			throws Exception {
		return captureCurrentRegressionSnapshots(dataDir, outputDir, TARGET_QUERIES);
	}

	static List<CapturedRegressionSnapshot> captureCurrentRegressionSnapshots(Path dataDir, Path outputDir,
			List<TargetQuery> targetQueries)
			throws Exception {
		LinkedHashMap<Theme, List<TargetQuery>> targetsByTheme = new LinkedHashMap<>();
		for (TargetQuery targetQuery : targetQueries) {
			targetsByTheme.computeIfAbsent(targetQuery.theme(), ignored -> new ArrayList<>())
					.add(targetQuery);
		}

		List<CapturedRegressionSnapshot> snapshots = new ArrayList<>();
		for (Map.Entry<Theme, List<TargetQuery>> entry : targetsByTheme.entrySet()) {
			PreparedThemeStore preparedStore = prepareThemeStore(dataDir, entry.getKey());
			LmdbStore store = new LmdbStore(preparedStore.storeDirectory().toFile(), preparedStore.storeConfig());
			SailRepository repository = new SailRepository(store);
			QueryPlanCapture capture = new QueryPlanCapture();
			try {
				for (TargetQuery targetQuery : entry.getValue()) {
					Path snapshotPath = captureSnapshot(capture, repository, store, preparedStore.storeConfig(),
							outputDir,
							targetQuery);
					QueryPlanSnapshot snapshot = capture.readSnapshot(snapshotPath);
					snapshots.add(new CapturedRegressionSnapshot(targetQuery, snapshotPath, snapshot));
					BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
				}
			} finally {
				shutdownAndRelease(repository, store);
				BenchmarkJoinEstimatorSupport.deleteStoreDirectory(preparedStore.storeDirectory());
			}
		}
		return snapshots;
	}

	static List<TargetQuery> resolveTargetQueries(String configuredKeys) {
		if (configuredKeys == null || configuredKeys.isBlank()) {
			return TARGET_QUERIES;
		}
		List<TargetQuery> selected = new ArrayList<>();
		for (String token : configuredKeys.split(",")) {
			String trimmed = token.trim();
			if (trimmed.isEmpty()) {
				continue;
			}
			int separator = trimmed.indexOf(':');
			if (separator < 0 || separator == trimmed.length() - 1) {
				throw new IllegalArgumentException("Expected THEME:index but got `" + trimmed + "`");
			}
			Theme theme = Theme.valueOf(trimmed.substring(0, separator));
			int queryIndex = Integer.parseInt(trimmed.substring(separator + 1));
			selected.add(resolveTargetQuery(theme, queryIndex));
		}
		return selected;
	}

