	private static PreparedThemeStore prepareThemeStore(Path dataDir, Theme theme) throws Exception {
		LmdbStoreConfig storeConfig = ConfigUtil.createConfig();
		int[] primeIndexes = LEARNED_FILTER_PRIMES.getOrDefault(theme, ints());
		String primeKey = IntStream.of(primeIndexes)
				.mapToObj(String::valueOf)
				.collect(java.util.stream.Collectors.joining("-"));
		String storeKey = PERSISTENT_STORE_KEY_PREFIX + "/" + theme.name() + "/"
				+ (primeKey.isEmpty() ? "no-prime" : primeKey);
		BenchmarkJoinEstimatorSupport.ThemeRegressionStore preparedStore = BenchmarkJoinEstimatorSupport
				.prepareThemeRegressionStore(
						dataDir.resolve(theme.name()),
						storeKey,
						storeDirectory -> {
							LmdbStore store = new LmdbStore(storeDirectory.toFile(), storeConfig);
							SailRepository repository = new SailRepository(store);
							try {
								BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
								loadThemeData(repository, theme);
								BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);
								primeLearnedFilterStats(repository, theme);
								BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
							} finally {
								shutdownAndRelease(repository, store);
							}
						});
		if (preparedStore.reused()) {
			System.out.println("Reusing persistent store " + preparedStore.storeDirectory()
					+ " for regression analysis " + theme.name() + ". " + PERSISTENT_STORE_HINT);
		}
		return new PreparedThemeStore(preparedStore.storeDirectory(), storeConfig);
	}

	private static void loadThemeData(SailRepository repository, Theme theme) throws IOException {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			RDFInserter inserter = new RDFInserter(connection);
			ThemeDataSetGenerator.generate(theme, inserter);
			connection.commit();
		}
	}

	private static void primeLearnedFilterStats(SailRepository repository, Theme theme) {
		for (int queryIndex : LEARNED_FILTER_PRIMES.getOrDefault(theme, ints())) {
			primeLearnedFilterStats(repository, theme, queryIndex);
		}
	}

	private static void primeLearnedFilterStats(SailRepository repository, Theme theme, int queryIndex) {
		String query = ThemeQueryCatalog.queryFor(theme, queryIndex);
		long expected = ThemeQueryCatalog.expectedCountFor(theme, queryIndex);
		long actual = executeQuery(repository, query);
		if (actual != expected) {
			throw new AssertionError("Unable to prime learned filter stats: theme=" + theme + ", queryIndex="
					+ queryIndex + ", expected=" + expected + ", actual=" + actual);
		}
	}

	private static long executeQuery(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query)
					.evaluate()
					.stream()
					.count();
		}
	}

	private static Path captureSnapshot(QueryPlanCapture capture, SailRepository repository, LmdbStore store,
			LmdbStoreConfig storeConfig, Path outputDir, TargetQuery targetQuery) throws IOException {
		String query = ThemeQueryCatalog.queryFor(targetQuery.theme(), targetQuery.queryIndex());
		var benchmarkQuery = ThemeQueryCatalog.benchmarkQueryFor(targetQuery.theme(), targetQuery.queryIndex());
		FeatureFlagCollector featureFlags = new FeatureFlagCollector()
				.addValue("regression.themeName", () -> targetQuery.theme().name())
				.addValue("regression.queryIndex", () -> Integer.toString(targetQuery.queryIndex()))
				.addValue("regression.regressionClass", targetQuery::regressionClass)
				.addValue("regression.firstDivergenceGuess", targetQuery::firstDivergenceGuess)
				.addReflectiveGetter("lmdbStore.writable", store, "isWritable")
				.addReflectiveGetter("lmdbConfig.tripleIndexes", storeConfig, "getTripleIndexes")
				.addReflectiveGetter("lmdbConfig.forceSync", storeConfig, "getForceSync")
				.addReflectiveField("lmdbConfig.autoGrow", storeConfig, "autoGrow")
				.addReflectiveGetter("lmdbConfig.valueDbSize", storeConfig, "getValueDBSize")
				.addReflectiveGetter("lmdbConfig.tripleDbSize", storeConfig, "getTripleDBSize");
		QueryPlanCapture.registerConfiguredFeatureFlags(featureFlags);

		QueryPlanCaptureContext context = QueryPlanCaptureContext.builder()
				.outputDirectory(outputDir)
				.queryId("lmdb-regression-" + targetQuery.theme().name().toLowerCase() + "-q"
						+ targetQuery.queryIndex())
				.queryString(query)
				.benchmark("LmdbRegressionPlanCaptureTest")
				.addMetadata("store", "lmdb")
				.addMetadata("storeMode", "theme-local")
				.addMetadata("theme", targetQuery.theme().name())
				.addMetadata("queryIndex", Integer.toString(targetQuery.queryIndex()))
				.addMetadata("queryName", benchmarkQuery.getName())
				.addMetadata("regressionClass", targetQuery.regressionClass())
				.addMetadata("firstDivergenceGuess", targetQuery.firstDivergenceGuess())
				.addMetadata("expectedCount",
						Long.toString(
								ThemeQueryCatalog.expectedCountFor(targetQuery.theme(), targetQuery.queryIndex())))
				.addMetadata(QueryPlanCapture.metadataFromSystemProperties())
				.featureFlagCollector(featureFlags)
				.tupleExprRenderer(LmdbRegressionAnalysisSupport::renderTupleExprWithIr)
				.build();

		try (SailRepositoryConnection connection = repository.getConnection()) {
			return capture.captureAndWrite(context, () -> {
				var tupleQuery = connection.prepareTupleQuery(query);
				tupleQuery.setMaxExecutionTime(30);
				return tupleQuery;
			});
		}
	}

	private static String renderTupleExprWithIr(TupleExpr tupleExpr) {
		TupleExprIRRenderer.Config config = new TupleExprIRRenderer.Config();
		config.verifyRoundTrip = false;
		return new TupleExprIRRenderer(config).render(tupleExpr);
	}

	private static void shutdownAndRelease(SailRepository repository, LmdbStore store) throws IOException {
		try {
			BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		} finally {
			repository.shutDown();
		}
	}

	private static String debugMetric(QueryPlanExplanation explanation, String key) {
		if (explanation == null || explanation.getDebugMetrics() == null) {
			return "<missing>";
		}
		return nonBlank(explanation.getDebugMetrics().get(key));
	}

	private static String nonBlank(String value) {
		return value == null || value.isBlank() ? "<missing>" : value;
	}

	private static int[] ints(int... values) {
		return values;
	}

	private static TargetQuery target(Theme theme, int queryIndex, String regressionClass,
			String firstDivergenceGuess) {
		return new TargetQuery(theme, queryIndex, regressionClass, firstDivergenceGuess);
	}

	private static TargetQuery resolveTargetQuery(Theme theme, int queryIndex) {
		for (TargetQuery targetQuery : TARGET_QUERIES) {
			if (targetQuery.theme() == theme && targetQuery.queryIndex() == queryIndex) {
				return targetQuery;
			}
		}
		throw new IllegalArgumentException("No targeted regression query configured for " + theme + ":" + queryIndex);
	}

	record TargetQuery(Theme theme, int queryIndex, String regressionClass, String firstDivergenceGuess) {
	}

	record CapturedRegressionSnapshot(TargetQuery targetQuery, Path snapshotPath, QueryPlanSnapshot snapshot) {
	}

	private record PreparedThemeStore(Path storeDirectory, LmdbStoreConfig storeConfig) {
	}
